  "asset-001": { steps: ["Create a pack of 20 Lightroom desktop and mobile presets: 5 warm lifestyle presets, 5 cool tones presets, 5 moody presets, and 5 light and airy presets.", "Develop each preset style by editing a test set of 10 varied photos — indoor, outdoor, portrait, and flat lay — to ensure broad compatibility.", "Build the 5 warm lifestyle presets with golden undertones, boosted highlights, and slightly desaturated blues.", "Build the 5 cool tones presets with lifted shadows, teal-tinted shadows, and reduced orange saturation.", "Build the 5 moody presets with crushed blacks, rich contrast, and muted overall saturation; 5 light and airy with lifted exposure, faded blacks, and a clean white base.", "Export as .xmp files for desktop Lightroom and .dng files for Lightroom Mobile; bundle in a ZIP with an installation guide PDF.", "Create before/after comparison mockups and list with Lightroom presets, photo editing, and Instagram preset pack keywords."] },
  "asset-002": { steps: ["Create a 20-brush Procreate brush set: 5 inking brushes, 5 watercolour texture brushes, 5 chalk and pastel brushes, and 5 stamp brushes.", "Develop each brush by testing on a blank 3000×3000px canvas at 300 DPI, refining pressure curve, taper, and scatter settings.", "Build 5 inking brushes — hard liner, tapered liner, brush pen, rough pen, and stipple — with fine pressure response for illustration.", "Build 5 watercolour brushes — wet wash, dry edge, bloom, texture bleed, and background wash — for natural media emulation.", "Build 5 chalk and pastel brushes for a hand-drawn tactile look, and 5 stamp brushes (leaf, flower, star, texture dot, and circle) for pattern use.", "Export the full set as a single .brushset file and individual .brush files; include a swatch sheet PDF showing each brush stroke.", "Create styled iPad flat-lay mockups showing the brushes in use and list with Procreate brushes, digital art tools, and iPad artist keywords."] },
  "asset-003": { steps: ["Create 5 Procreate colour palette packs of 10 swatches each: warm neutrals, cool minimalist, earthy botanicals, retro pastels, and moody darks.", "Research and curate each palette for harmony — using analogous, triadic, or complementary colour theory as appropriate.", "Build the warm neutrals palette with ivory, sand, blush, terracotta, and warm brown tones across 10 graduated swatches.", "Build the cool minimalist palette with icy blues, grey-whites, muted lavenders, and cool sage across 10 swatches.", "Build the earthy botanicals, retro pastels, and moody darks palettes — each 10 swatches with hex codes documented.", "Export each palette as a .swatches file for Procreate and include a PDF reference sheet with hex values for each colour.", "Create styled digital art mockups showing palettes applied to illustrations and list with Procreate colour palette, digital art swatch, and iPad art keywords."] },
  "asset-004": { steps: ["Create or curate a 30-image styled stock photo bundle: 10 flat lay images, 10 lifestyle images, and 10 desktop/workspace images.", "Use a consistent visual aesthetic — neutral background palette, warm natural light, and cohesive styling across all 30 images.", "Style and shoot 10 flat lay images with consistent props: notebook, coffee, plants, and neutral fabric — varying layouts.", "Style and shoot 10 lifestyle images featuring hands writing, typing, or working in a clean minimal environment.", "Style and shoot 10 desktop/workspace images at varying angles — overhead, 45°, eye level — showing clean desk setups.", "Edit all 30 images in Lightroom to a consistent preset look and export as high-resolution JPEGs (3000px+ minimum dimension).", "Create a collage preview image and list with styled stock photos, blog photography, and flat lay stock image keywords."] },
